@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <small class="text-muted ms-2">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial notifications during SSR — this data is included in the
        // server-rendered HTML and persisted into the interactive runtime via
        // Blazor's component state, so it won't be fetched again.
        _notifications = NotificationService.GetNotifications();
        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live and interactive
            // in the browser — never during the static SSR pass.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            // Simulate external notifications arriving
            NotificationService.SimulateNewNotification();

            var newItems = NotificationService.GetNotificationsSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                _lastSeenId = newItems.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        // Clean cancellation — stops the polling loop with no leaked tasks.
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

